"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[5348],{479(e,t,i){i.r(t),i.d(t,{assets:()=>h,contentTitle:()=>a,default:()=>c,frontMatter:()=>o,metadata:()=>r,toc:()=>l});var n=i(4848),s=i(8453);const o={},a="Epilogue",r={id:"mirror-realm/epilogue",title:"Epilogue",description:"Taiwan Edition v3.5 (Added \u3008Two and a Half Pengguang Industrial cross-company observation)",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/mirror-realm/epilogue.md",sourceDirName:"mirror-realm",slug:"/mirror-realm/epilogue",permalink:"/MythogenEngine/en/docs/mirror-realm/epilogue",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 19: Reorganization and Survivors",permalink:"/MythogenEngine/en/docs/mirror-realm/ch19"},next:{title:"GameVictory \u2014 Book Info Page",permalink:"/MythogenEngine/en/docs/GameVictory/INFO_PAGE"}},h={},l=[{value:"Taiwan Edition v3.5 (Added \u3008Two and a Half: Before\u3009: Pengguang Industrial cross-company observation)",id:"taiwan-edition-v35-added-two-and-a-half-before-pengguang-industrial-cross-company-observation",level:2},{value:"I. The Study",id:"i-the-study",level:2},{value:"II. Both Sides",id:"ii-both-sides",level:2},{value:"II &amp; a Half. Before",id:"ii--a-half-before",level:2},{value:"III. The Mask",id:"iii-the-mask",level:3},{value:"IV. Breathing",id:"iv-breathing",level:3},{value:"V. Another Layer",id:"v-another-layer",level:3},{value:"VI. Never Intended To",id:"vi-never-intended-to",level:3},{value:"VII. Fracture",id:"vii-fracture",level:3},{value:"VIII. The Map",id:"viii-the-map",level:3},{value:"IX. No One Applauding",id:"ix-no-one-applauding",level:3}];function d(e){const t={code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",hr:"hr",li:"li",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,s.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"epilogue",children:"Epilogue"})}),"\n",(0,n.jsx)(t.h2,{id:"taiwan-edition-v35-added-two-and-a-half-before-pengguang-industrial-cross-company-observation",children:"Taiwan Edition v3.5 (Added \u3008Two and a Half: Before\u3009: Pengguang Industrial cross-company observation)"}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"i-the-study",children:"I. The Study"}),"\n",(0,n.jsx)(t.p,{children:"I anticipated they might be this kind of people."}),"\n",(0,n.jsx)(t.p,{children:"I chose to assume they weren't. Just get the work done."}),"\n",(0,n.jsx)(t.p,{children:"These words I say twice in this book, once at the beginning and once at the end. The hundreds of thousands of words in between are the price paid for this sentence."}),"\n",(0,n.jsx)(t.p,{children:"It is now February 1026. I am sitting in the study. Outside the window is late winter in Jade Mirror City\u2014gray skies, the wind entering the house but not quite cold enough. My computer is on. A Word document open. I have been writing for exactly a year. Today I arrived at the epilogue."}),"\n",(0,n.jsx)(t.p,{children:"I used to think that on the day I wrote the epilogue, I would know what to write."}),"\n",(0,n.jsx)(t.p,{children:'Now, sitting here, I realize I don\'t know. I just\u2014have nowhere else to push this. The previous chapters are all completely written. Lin Zhaoming\'s story, from being called away in the pantry, to the PIP, to the Gray Rock, to the final refusal, to the N+1 severance package, to the "invalid credentials" login screen\u2014it has all been written. From the day he "assumed they weren\'t" to the day he realized "they actually were," every step in between is right here.'}),"\n",(0,n.jsx)(t.p,{children:"But this book cannot end here."}),"\n",(0,n.jsx)(t.p,{children:'The reason it cannot end here is simple: if a reader finishes the first nineteen chapters and closes the book, they should take away something. Not just the words "so tragic." Not just the comment "this company sucks." It should be\u2014a map they can carry out into the world. A map bought with my four years and several lives I could not save.'}),"\n",(0,n.jsx)(t.p,{children:'This map exists in the form of feelings in the first nineteen chapters. Lin Zhaoming, inside the office, could not name anything. He could only feel. His body knew years before his words did\u2014but he couldn\'t translate this "bodily knowing" into something portable.'}),"\n",(0,n.jsx)(t.p,{children:"The epilogue is the first and only place where the author can name things directly."}),"\n",(0,n.jsx)(t.p,{children:"I will try."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"But in writing this epilogue, I face a choice: write it shallowly so more people can easily understand, or write it deeply so fewer people take away the complete picture. I chose the latter. The reason is\u2014this observation is specific enough that simplifying it would lose it entirely. Readers have already seen simplified versions in many other places; I have nothing to add to those."}),"\n",(0,n.jsx)(t.p,{children:"But the cost of this choice is that some sections will be difficult. I try to keep a reader-friendly tone while writing, but a few sections are inherently abstract."}),"\n",(0,n.jsx)(t.p,{children:"So here I give you a map, letting you know the road ahead."}),"\n",(0,n.jsx)(t.p,{children:"The epilogue is divided into nine sections:"}),"\n",(0,n.jsxs)(t.ul,{children:["\n",(0,n.jsx)(t.li,{children:"I. \u3008The Study\u3009: The section you are reading right now. Easy."}),"\n",(0,n.jsx)(t.li,{children:"II. \u3008Both Sides\u3009: Easy. The author explains their position."}),"\n",(0,n.jsx)(t.li,{children:(0,n.jsx)(t.strong,{children:"II & a Half. \u3008Before\u3009: Medium, personal. Cross-company observation, an evidence base of the system rather than the individual."})}),"\n",(0,n.jsx)(t.li,{children:(0,n.jsx)(t.strong,{children:"III. \u3008The Mask\u3009: Abstract. The framework of the central concept. If you lose the thread, you can jump to the fourth section."})}),"\n",(0,n.jsx)(t.li,{children:(0,n.jsx)(t.strong,{children:"IV. \u3008Breathing\u3009: Abstract, emotionally heavy. The anchor of the moral frame. If you skip III and IV, I recommend you at least come back and try reading section IV, because what it explains will be referenced later."})}),"\n",(0,n.jsx)(t.li,{children:"V. \u3008Another Layer\u3009: Relatively easy to read, emotionally heavy."}),"\n",(0,n.jsx)(t.li,{children:(0,n.jsx)(t.strong,{children:"VI. \u3008Never Intended To\u3009: Medium difficulty. Contains industry-specific references."})}),"\n",(0,n.jsx)(t.li,{children:"VII. \u3008Fracture\u3009: Easy to read, personal, emotionally heavy."}),"\n",(0,n.jsx)(t.li,{children:"VIII. \u3008The Map\u3009: Easy, highly practical. A takeaway list."}),"\n",(0,n.jsx)(t.li,{children:"IX. \u3008No One Applauding\u3009: Short, easy, closing."}),"\n"]}),"\n",(0,n.jsx)(t.p,{children:"If you only have time for three sections, read: I, VIII, IX.\r\nIf you only have time for five sections, add: II, VII.\r\nIf you want to read all of it, just read in order."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"If you read certain sections and lose the thread, you have two options."}),"\n",(0,n.jsx)(t.p,{children:"The first option: jump. Jump to the next section. The later sections do not rely on all the prior technical details. Some ideas echo across sections, so bumping back into the same idea after skipping might actually make it clearer, given the different angle."}),"\n",(0,n.jsx)(t.p,{children:"The second option\u2014this I must say directly, because not saying it would be another kind of mask\u2014"}),"\n",(0,n.jsx)(t.p,{children:'There are now tools that can help you unpack a dense text. You can paste a paragraph of this epilogue into it and ask, "What does this paragraph mean?", "Rephrase it in simpler words," or "Give an example." What it answers may not be complete, but it will help you catch a thread so you can keep reading.'}),"\n",(0,n.jsx)(t.p,{children:"The reason I can suggest this directly is because when I was writing this book myself, I used the same tools as a mirror. I used them to reflect my own fragments. When I had a pile of feelings but couldn't find a framework, I would speak a paragraph, it would reflect it back, and I would look at the reflection to see what was right, what was wrong, and what I hadn't figured out myself yet. Its function is not as a producer. It is a mirror."}),"\n",(0,n.jsx)(t.p,{children:"Readers using these tools to reflect my framework\u2014is the exact same action, just with the direction reversed."}),"\n",(0,n.jsx)(t.p,{children:"There is an awkward layer here I must acknowledge: among the things this book critiques is the commercial hype using AI for window dressing\u2014talking about AI in town halls, writing AI on slide decks, AI in press releases, while the actual thing produced is corporate valuation rather than a product. This will be explained in detail in section VI, \u3008Never Intended To\u3009."}),"\n",(0,n.jsx)(t.p,{children:"And now I am telling you to use these kinds of tools to read my book. I will not resolve this contradiction."}),"\n",(0,n.jsx)(t.p,{children:"I merely acknowledge\u2014tools are neutral. The same knife can chop vegetables, kill a person, or carve wood. The question isn't the knife; it's the hand wielding it. A system using AI as a narrative wrapper to fabricate a capability roadmap to support valuation\u2014is one use. A reader using AI as a mirror to reflect a text they don't understand, allowing them to access a framework they otherwise couldn't\u2014is another use."}),"\n",(0,n.jsx)(t.p,{children:"Both uses share the same tool. But the outcomes produced are opposites."}),"\n",(0,n.jsx)(t.p,{children:"The hand you are using right now is yours."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"OK, housekeeping done. Back to the epilogue itself."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"ii-both-sides",children:"II. Both Sides"}),"\n",(0,n.jsx)(t.p,{children:"That I can write this book is luck. Not a marker of character."}),"\n",(0,n.jsx)(t.p,{children:"I have to state this clearly very early on, otherwise the entirety of this epilogue will be misread."}),"\n",(0,n.jsx)(t.p,{children:"I have been an expat employee. I have also been a local regional employee. This combination is highly uncommon in this industry. Most people only experience one side. Those who are expats see policies, strategies, town hall slide decks, and quarterly numbers. What they do not see are the under-the-table maneuvering\u2014not because they aren't smart, but because they aren't on the ground. The people on the ground every day wouldn't raise their hands in a town hall and say, \"This strategy is doing completely different things underground.\" No one would. So the policies look pristinely clean."}),"\n",(0,n.jsx)(t.p,{children:"Those who are regional employees see the opposite side\u2014under-the-table maneuvering, office politics, who is in whose circle, how promotions actually happen, and how HR handles logic gaps in specific cases. But they don't see the source of the strategy. Because regional employees have no access. They merely receive."}),"\n",(0,n.jsx)(t.p,{children:"If you have only been on one side, you will think you've seen the whole picture. Expats think the company is what the town hall looks like. Regional employees think the company is what the pantry looks like. Neither side is wrong, but both sides are fragments."}),"\n",(0,n.jsx)(t.p,{children:"I did both. I was an expat first, then a regional employee later. With a few years in between. Those middle few years are critical\u2014if I had done both consecutively, I might not have been able to separate the two frames. But with a gap of a few years, the day I returned to the other side of the same industry, I brought memories. I remembered the voice of the town hall, and simultaneously, I was experiencing the voice of the office. Both voices were in my head at the same time, cross-referencing each other."}),"\n",(0,n.jsx)(t.p,{children:"This cross-reference is the source code of this book."}),"\n",(0,n.jsx)(t.p,{children:"Without this cross-reference, I would be like everyone else\u2014thinking my private experience was purely private. Thinking this specific company was uniquely terrible. Thinking I was exceptionally unlucky. Thinking this was a Jade Mirror Island problem, or a regional problem, or a local culture problem."}),"\n",(0,n.jsx)(t.p,{children:"With this cross-reference, I finally started to see\u2014this is not a private experience. This is an instance of a broader structure. I had seen an earlier version of this same structure in other places from the expat perspective. At the time, I couldn't name it because in the expat view, I only saw the strategy side. Now, returning to the regional perspective, I finally had all the fragments from both sides. Only then could I begin to piece them together."}),"\n",(0,n.jsx)(t.p,{children:"But I must emphasize\u2014this is luck."}),"\n",(0,n.jsx)(t.p,{children:'I did not consciously arrange to experience both sides. I didn\'t see through everything and decide, "Well then, let me try both sides to write a book later." Absolutely not. My choices at every step were driven by immediate reasons\u2014finding a job, family, moving, getting laid off, finding another job\u2014just like everyone else. I had no grand foresight. I am merely piecing the puzzle together after the fact.'}),"\n",(0,n.jsx)(t.p,{children:"And piecing the puzzle together post-mortem\u2014is something very few people do. Most people, even if they have access to both sides, will not merge the two frames. Because merging them is incredibly painful. The reason for this pain won't be explained until the core of this book."}),"\n",(0,n.jsx)(t.p,{children:"So this book is not a product of courage. It is a product of conditions. I had the fragments of both sides, I had time, and I had a baseline that didn't require me to burn through cash every month\u2014at least for now."}),"\n",(0,n.jsx)(t.p,{children:"These are all conditions."}),"\n",(0,n.jsx)(t.p,{children:"If I am to take any credit for this book, the only credit I'll accept is this: at the moment the conditions aligned, I did not waste them."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"ii--a-half-before",children:"II & a Half. Before"}),"\n",(0,n.jsx)(t.p,{children:"What I am writing now\u2014the years at Lingyun Synthesis\u2014was not my first time seeing this shape."}),"\n",(0,n.jsx)(t.p,{children:'In my first few years in the industry, I worked at a company called Pengguang Industrial. They produced disposable batteries. I was young then, working at the grassroots level, watching a group sitting above us called the Strategy Development Department. They were considered the "elites" within the company. They had their own floor, their own jargon, and their own discourse on "how to be responsible to the company."'}),"\n",(0,n.jsx)(t.p,{children:'The core of that discourse was: "Being cruel to the bottom is the only way to be kind to the majority."'}),"\n",(0,n.jsx)(t.p,{children:'When I heard that back then, I thought, "Fuck off." But I admit, it had a logical structure on the surface\u2014the company was in a sunset industry, a red ocean market where profit margins were paper-thin. If we didn\'t squeeze to the absolute extreme, the factories would move away, jobs would vanish, and everyone would die together. So the extreme squeezing was necessary. Whistleblowing and mutual surveillance were necessary. Changing cardboard packaging to shrink wrap to save a few cents was necessary. Outsourcing the automation of an entire line to dozens of disjointed vendors, producing a "customized system" with beautiful dashboards but actual bottlenecks everywhere, was necessary.'}),"\n",(0,n.jsx)(t.p,{children:"My explanation at the time was: This bullshit discourse is a product of economic pressure. People in a sunset industry, pushed to the brink by the ledger, turn out this way. If you removed the economic pressure, this system would disappear."}),"\n",(0,n.jsx)(t.p,{children:"I carried this explanation with me for a full decade."}),"\n",(0,n.jsx)(t.p,{children:"But during those years at Pengguang Industrial, I registered an observation. I didn't name it then; I just filed it away."}),"\n",(0,n.jsx)(t.p,{children:"The heads of the Strategy Development Department changed on average every one or two years. Some left after a few months. During my time there, it changed at least five or four times. And every person who sat in that chair had the exact same shape. The identical ruthlessness. The identical discourse. The identical contempt for those below. The identical fluency towards those above. Even the mannerisms were alike\u2014the angle of a shifting gaze, the speed of reframing, the reflex of digesting an awkward fact within three seconds."}),"\n",(0,n.jsx)(t.p,{children:"At the time, I thought: Strange. If this is a personal issue of the individual, going through five or six people, you'd bound to find at least one who's different. But no. Not a single one."}),"\n",(0,n.jsx)(t.p,{children:"I had no answer back then. I simply filed the observation away."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"Then I went to Lingyun Synthesis."}),"\n",(0,n.jsx)(t.p,{children:'Lingyun Synthesis is not a sunset industry. It has money. It has scale. It has a globally recognized brand. It has HR processes, compliance training, town halls preaching "People First," and DEI policy documents. It has absolutely none of Pengguang Industrial\'s "forced by the ledger" excuses.'}),"\n",(0,n.jsx)(t.p,{children:'Yet the level of bullshit discourse\u2014using the phrase "100 times worse" is honestly conservative.'}),"\n",(0,n.jsx)(t.p,{children:"And what disoriented me the most during that period wasn't the bullshit itself. It was\u2014the people I bumped into there, I recognized their shape."}),"\n",(0,n.jsx)(t.p,{children:"They were the exact same shape as the people sitting in that Strategy Development Department chair at Pengguang Industrial. The same identical ruthlessness. The identical fluency. The identical contempt for subordinates disguised as care. The identical reflex of digesting an awkward fact in three seconds flat."}),"\n",(0,n.jsx)(t.p,{children:"But Lingyun Synthesis had no sunset industry excuse."}),"\n",(0,n.jsx)(t.p,{children:"And the level of bullshit\u2014I don't know how else to describe it\u2014if Pengguang Industrial was a 30 out of 100, Lingyun Synthesis was a solid 100."}),"\n",(0,n.jsx)(t.p,{children:"Back at Pengguang Industrial, I thought 30 points was the absolute limit. I thought human nature combining with systemic cruelty to kill people, with no one caring and no one looking, was the absolute farthest this sort of thing could go. I spent a full ten years explaining it to myself: this is a mutation born of extreme environments; this isn't the norm; this is forced by the ledger, so remove the ledger and it's gone."}),"\n",(0,n.jsx)(t.p,{children:"Then I went to a place with no structural ledger constraints and saw a full 100 points."}),"\n",(0,n.jsx)(t.p,{children:"My decade-long explanation severed precisely in that moment."}),"\n",(0,n.jsx)(t.p,{children:"In that moment\u2014perhaps it wasn't a single moment, but a buildup over a full year\u2014the explanation I'd carried for ten years snapped."}),"\n",(0,n.jsx)(t.p,{children:"If this bullshit discourse were the product of economic pressure, it shouldn't exist in a massively wealthy company. But it did. And it was more refined, harder to pierce, incredibly complete."}),"\n",(0,n.jsx)(t.p,{children:"Which means\u2014the root cause was never economic pressure."}),"\n",(0,n.jsx)(t.p,{children:"Economic pressure is merely an amplifier."}),"\n",(0,n.jsx)(t.p,{children:"The root cause is: The selection mechanism of this system carves out a specific shape. Those sitting steadily in those chairs already completely fit that shape. Those who sit unsteadily are swapped out within months. The system doesn't need to educate anyone, doesn't need to instill ideology, doesn't need endless meetings to align values. It only requires short-cycle elimination. Those who sit steadily, stay. Those who sit unsteadily, leave. After a few cycles, what remains is not \"ordinary people trapped\"\u2014what remains is a batch of meticulously selected individuals whose core capability is maintaining the mask with absolute fluency."}),"\n",(0,n.jsx)(t.p,{children:"This mechanism operates in the sunset industry of Pengguang Industrial. It also operates in the wealthy Lingyun Synthesis. It has nothing to do with economic pressure. Economic pressure merely gives its surface an extra layer of narrative cover\u2014providing the people sitting in those chairs a convenient justification for themselves. Strip away the narrative wrapper, and the shape remains."}),"\n",(0,n.jsx)(t.p,{children:"And when writing this book, the one sentence I constantly had to remind myself was\u2014do not let readers think this is a uniquely Lingyun Synthesis story. And do not let them think this is a sunset industry story."}),"\n",(0,n.jsx)(t.p,{children:"Both framings are safety nets. Both will assist the reader in evading the actual problem."}),"\n",(0,n.jsx)(t.p,{children:'The true problem is: as long as those few conditions are met, this shape will appear anywhere. Regardless of the industry, regardless of nationality, regardless of whether the company is rich or not, regardless of how "progressive" the company appears to be on the surface. Pengguang Industrial is the 30-point version. Lingyun Synthesis is the 100-point version. And every single tick mark between 30 and 100 points\u2014right now, at this very moment in some corner of the world\u2014someone is currently experiencing it.'}),"\n",(0,n.jsx)(t.p,{children:"Not every company is like this. But a company not being like this doesn't mean it exists outside this spectrum\u2014it's just hovering at a very low tick mark. And when that tick mark starts to climb, from the inside, there are zero warning signs."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"I am so certain of this observation because I've seen it twice."}),"\n",(0,n.jsx)(t.p,{children:'Once is not enough. Once could mean your company is just exceptionally terrible, you\'re exceptionally unlucky, or you have a particularly evil boss. With an N=1 sample, you can\'t distinguish "individual" from "structural."'}),"\n",(0,n.jsx)(t.p,{children:"Twice, across companies, across industries, across geographic regions, across economic conditions\u2014and still persisting across multiple personnel permutations within each company\u2014only then is it enough for you to say: This is not individual. This is a reproducible shape."}),"\n",(0,n.jsx)(t.p,{children:"And the implications of this reproducible shape are utterly devastating. It means: the boss you are facing right now in your office, the things he does, are not because he is him. The things he does are because he sits in that chair. If you swap him out today and someone else sits there tomorrow, what you will experience\u2014will be fundamentally the same."}),"\n",(0,n.jsx)(t.p,{children:'This implication is cruel to the victim. Because it strips away the one hope that could carry you through tough times: "It\'ll be better once this boss leaves." That hope is false. The next one will be the exact same shape.'}),"\n",(0,n.jsx)(t.p,{children:"But this implication is completely essential for understanding. Because it shifts your anger away from a person and redirects it back to a system. And anger at a system has a completely different quality than anger at a person. The former doesn't have a face you can fixate on, but the former is far more accurate."}),"\n",(0,n.jsx)(t.p,{children:"In Section VII, I will recount how my belief system ruptured. The origin point of that rupture didn't actually lie in the death of November 1024. The origin point was earlier\u2014in my second year at Lingyun Synthesis, when I bumped into that shape, retrieved the Pengguang Industrial file, overlaid the two, and realized they were the exact same blueprint."}),"\n",(0,n.jsx)(t.p,{children:"In that moment, ten years of my explanations snapped."}),"\n",(0,n.jsx)(t.p,{children:"The day of the death simply made the rupture final."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h3,{id:"iii-the-mask",children:"III. The Mask"}),"\n",(0,n.jsxs)(t.p,{children:["The book is titled ",(0,n.jsx)(t.em,{children:"Mirror Realm: The Murder in the Masked System"}),"."]}),"\n",(0,n.jsx)(t.p,{children:"I didn't directly use the term \"Masked System\" even once in the first nineteen chapters. Inside the office, Lin Zhaoming couldn't say this term\u2014not because he didn't understand it, but because his body hadn't yet pieced together this frame. Now, in the epilogue, I can say it."}),"\n",(0,n.jsx)(t.p,{children:"The essence of the masked system is:"}),"\n",(0,n.jsx)(t.pre,{children:(0,n.jsx)(t.code,{children:"Speaking (Spoken) \u2260 Writing (Documents) \u2260 Doing (Actions)\n"})}),"\n",(0,n.jsx)(t.p,{children:"Three entirely distinct sets of things, maintaining a facade of uniformity. This is the masked system."}),"\n",(0,n.jsx)(t.p,{children:"This isn't anyone's conspiracy. This is a\u2014routine operating mode of the corporate world. If you pick any mid-to-large-sized company, you can verify this mechanism. They speak certain things (town halls, press releases, the CEO's LinkedIn posts). They write certain things (internal documents, policies, PIPs, contracts). They do certain things (the actual personnel decisions being made, the actual flow of resources, who actually gets the promotion). When the gap between these three sets of things is small, it's a relatively healthy company. When the gap between them is grotesquely large, yet the company still operates, that is the mature form of the masked system."}),"\n",(0,n.jsx)(t.p,{children:"When Lin Zhaoming entered the industry, he was already aware of its existence. He wasn't na\xefve. He knew that what is said and what is done are often different. Anyone who has spent a few years in the corporate world knows this. This isn't an insight; this is common sense."}),"\n",(0,n.jsx)(t.p,{children:"But what he didn't know was\u2014how absurd the extent could be."}),"\n",(0,n.jsx)(t.p,{children:'"People First" printed on a town hall slide, while a layoff list comes out three weeks later\u2014this he anticipated. This is normal corporate hypocrisy. He knew how to handle it.'}),"\n",(0,n.jsx)(t.p,{children:'But: after someone dies, a previously existing technical issue suddenly "never existed"\u2014'}),"\n",(0,n.jsx)(t.p,{children:"This, he did not anticipate."}),"\n",(0,n.jsx)(t.p,{children:'After the incident occurred, the ticket vanished. Comments were edited. He asked the adjacent team in the pantry, "What\'s going on with that null pointer issue now?" The other person looked at him, their eyes completely sincere and deeply confused\u2014"What null pointer?" At that moment, Lin Zhaoming finally understood: this wasn\'t an issue of "no one dares to mention it." "No one dares to mention it" is a conscious avoidance. This wasn\'t that. This was\u2014the event being processed into never having occurred. Across all systems, all records, and everyone\'s mouths, it never existed.'}),"\n",(0,n.jsx)(t.p,{children:'This is not hypocrisy. Hypocrisy is\u2014they know the truth, and then they speak the opposite. This is not that. This is\u2014the fact itself is disappeared. Even the anchor against which to speak the "opposite" is taken away.'}),"\n",(0,n.jsx)(t.p,{children:"This is the mature form of the masked system."}),"\n",(0,n.jsx)(t.p,{children:'A system that reaches this stage possesses a trait that is very difficult to describe: it no longer needs to distinguish between true and false. Because it no longer operates on the axis of "true vs. false." It operates on the axis of "whether the narrative can be maintained." If an event can maintain a narrative, it is true. If it cannot, it vanishes. There is no layer of "fact" operating as a baseline beneath it.'}),"\n",(0,n.jsx)(t.p,{children:'Hearing this, readers might think: "So this system will eventually blow up, right? Because reality will inevitably crash into it."'}),"\n",(0,n.jsx)(t.p,{children:"This is a reasonable deduction, but it is incorrect."}),"\n",(0,n.jsx)(t.p,{children:"Whether or not this system will blow up depends on how hard the reality it crashes into is. If the task this system performs is\u2014for instance\u2014a rocket meant to fly into space, it will blow up very quickly. Physics will rip its narrative apart."}),"\n",(0,n.jsx)(t.p,{children:'But if the task this system performs is\u2014some interfacing protocols, some firmware timings, the working conditions of some supplier engineers, the execution of certain policies\u2014then it can be maintained for a very long time. Because the "reality feedback" of these things is slow, distributed, and lacks a single catastrophic failure point. A supplier engineer dying\u2014is a distributed event to the system. A null pointer\u2014is a distributed event. An outsourced responsibility\u2014is a distributed event. No single event is massive enough to crash through the entire narrative all at once.'}),"\n",(0,n.jsx)(t.p,{children:"So the system can avoid blowing up for a long time."}),"\n",(0,n.jsx)(t.p,{children:'And during this "non-explosive" period, real things are still happening\u2014they just lack records.'}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"There is a deeper layer here that I must explain clearly, because it took me the longest time to accept."}),"\n",(0,n.jsx)(t.p,{children:"I used to believe\u2014that a system ridden with ambiguity exists because it \"failed to record the truth.\" Meaning, it intended to record it, but simply couldn't. Its tech system wasn't good enough. It lacked headcount. The categorizations weren't unified. Version control was flawed. Therefore, many things were lost in the cracks. If you fixed these technical issues, it would be able to record them."}),"\n",(0,n.jsx)(t.p,{children:"This understanding is wrong."}),"\n",(0,n.jsx)(t.p,{children:"The truth is the precise opposite: ambiguity itself is a feature of this system, not a bug."}),"\n",(0,n.jsx)(t.p,{children:'When your system operates on the axis of "whether the narrative can be maintained," you need a deeply ambiguous state of record-keeping. Because a clear record locks the facts into place, leaving the narrative no room to maneuver. If your ticket system had unified tracking numbers, perfect version traceability, and uneditable comments\u2014that null pointer issue could not have "never existed." It would be there forever.'}),"\n",(0,n.jsx)(t.p,{children:'So\u2014why do massive corporations spend so many years pushing for so-called "digital transformation," "ERP integration," or "systems consolidation"\u2014and taking so long to ultimately fail?'}),"\n",(0,n.jsx)(t.p,{children:"It is not due to technical difficulty."}),"\n",(0,n.jsx)(t.p,{children:'Technical difficulty is the surface reason. The deeper reason is: there is a cohort of people inside that system whose survival hinges on ambiguity. These people may not consciously sabotage digitalization\u2014they simply sit at every decision point and cast their vote for "let\'s delay this a bit," "let\'s run another round of evaluation," or "this isn\'t the priority right now." Every individual decision has a perfectly reasonable surface justification. But combined, the outcome is: ten years pass, and nothing gets done.'}),"\n",(0,n.jsx)(t.p,{children:"This isn't a conspiracy. This is emergent behavior."}),"\n",(0,n.jsx)(t.p,{children:'This point is profoundly important, because it explains why these systems self-reinforce. No one is sitting in a boss\'s chair saying, "We must never let digitalization succeed." But every microscopic, rational, individual decision adds up, producing the exact same effect.'}),"\n",(0,n.jsx)(t.p,{children:'It took me a long time to accept this. Because this overturned the default model of "organizations" I carried when I entered the industry\u2014I thought organizations were strictly top-down, with an executive layer setting the direction and cascading it down. I thought if something couldn\'t be done, it was because the executives refused to do it.'}),"\n",(0,n.jsx)(t.p,{children:"This model is fine for certain aspects. But for others, it is incredibly na\xefve."}),"\n",(0,n.jsx)(t.p,{children:'And for this specific aspect\u2014"why data cleaning still hasn\'t succeeded after ten years"\u2014the top-down model is completely wrong. At the execution level, no one votes for "success." Every single vote is cast for "delay." The emergent vote of the execution layer overpowers the stated direction of the executives.'}),"\n",(0,n.jsx)(t.p,{children:"And this emergent vote\u2014is driven by every individual's immediate self-interest. None of them want digitalization to succeed, because its success would force their own responsibilities to the surface. And they don't even need to discuss it amongst themselves. Each person has done the math on their own."}),"\n",(0,n.jsx)(t.p,{children:"This is the engine of the masked system."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h3,{id:"iv-breathing",children:"IV. Breathing"}),"\n",(0,n.jsx)(t.p,{children:"This is the section of the book I rewrote the most times, both forwards and backwards."}),"\n",(0,n.jsx)(t.p,{children:"Because there is a distinction here that took me years to think through. If this distinction isn't made crystal clear, the moral frame of the entire book collapses."}),"\n",(0,n.jsx)(t.p,{children:'I used to think\u2014the people in management who spoke lies, shirked responsibilities, severed ties with colleagues, and fabricated narratives\u2014were "genuinely buying into their own version of things." Which is to say, they didn\'t think they were lying. They lived inside a self-justifying reality bubble. They were victims of the structure, not perpetrators.'}),"\n",(0,n.jsx)(t.p,{children:"This understanding, I now believe, is wrong. Or to be more precise: it is partial, and partial to such a degree that it becomes completely wrong."}),"\n",(0,n.jsx)(t.p,{children:"We have to divide people into two categories here."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"The first category: Those who genuinely don\u2019t know about the middle layers."})}),"\n",(0,n.jsx)(t.p,{children:"These people exist. I don't deny it. In any corporate enterprise, there are many vertical layers, and the input received by the upper layers has already been filtered by the lower layers. These individuals\u2014typically managers separated by a significant distance, newly-arrived executives, or cross-functional colleagues\u2014receive a narrative that has already been scrubbed clean. They have no access to what actually happens in the middle layers."}),"\n",(0,n.jsx)(t.p,{children:'For this group, "genuinely buying into it" is an accurate description. The version they speak matches the version they received. They are not lying. They are merely relaying a version that they believe to be the truth.'}),"\n",(0,n.jsx)(t.p,{children:"The existence of these people is one of the mechanisms by which the system sustains itself. They are honest brokers\u2014honest within their own frame. But the content they are brokering has already been filtered. Thus, in effect, they are amplifying an inaccurate narrative. But they themselves don't know it."}),"\n",(0,n.jsx)(t.p,{children:"Towards this group, I hold no anger. I feel sadness. They are victims too, just a different kind of victim."}),"\n",(0,n.jsx)(t.p,{children:'But this group\u2014these "genuinely believing" ones\u2014make up the minority of those who tell lies within that system.'}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"The second category: Those who know, but choose to say the opposite."})}),"\n",(0,n.jsx)(t.p,{children:"These are the majority."}),"\n",(0,n.jsx)(t.p,{children:'It took me a very long time to accept this. Because acknowledging it required me to abandon a default assumption I carried when I entered the industry\u2014namely, "human beings are rational creatures; to commit a bad act, there must be a reason they can use to justify it to themselves." I thought if a person did something wrong, they must have an internal narrative explaining to themselves that what they did was reasonable. Otherwise, they wouldn\'t be able to do it.'}),"\n",(0,n.jsx)(t.p,{children:"This assumption was na\xefve."}),"\n",(0,n.jsx)(t.p,{children:"The actual mechanism operates like this:"}),"\n",(0,n.jsx)(t.p,{children:"A system has been running for a decade or two. Every cycle, it is picking people. Those unable to fabricate narratives leave\u2014they fail to get promoted, they become unhappy, they get marginalized, and eventually, they go. Those who can\u2014the more effortlessly, the better\u2014are promoted. They are given more power. They get seated closer to the core. Then they train the next batch."}),"\n",(0,n.jsx)(t.p,{children:'After several cycles, the remaining people are not "ordinary folks trapped in a bind." The remaining individuals are\u2014a batch of thoroughly vetted people. Their core competency is the collective fabrication of narratives.'}),"\n",(0,n.jsx)(t.p,{children:"The traits of this cohort:"}),"\n",(0,n.jsx)(t.p,{children:"They have an unspoken understanding\u2014one speaks half a sentence, the next knows exactly how to catch it; one shifts their eyes, the next knows exactly where to slide the knife; one writes the meeting notes, the next knows exactly which item those notes should omit. This understanding requires zero prep meetings because they have been mutually calibrating themselves for years, sometimes decades."}),"\n",(0,n.jsx)(t.p,{children:"The speed and fluency of their narrative fabrication reach a level where you can't even tell they are improvising. In a meeting, if an awkward fact surfaces, they can collectively reframe that fact into something entirely different within three seconds\u2014with absolutely zero visible signals during the process. No eye contact. No pause. No hesitation. They are just fluent."}),"\n",(0,n.jsx)(t.p,{children:'When faced with scrutiny, their default reflex is\u2014to reframe the question as the personal issue of the questioner themselves. "You\'ve been under a lot of pressure lately." "You have some communication challenges." "Your perception is slightly off." The speed of this reframing is faster than the question itself. This is not a strategy. This is an instinct.'}),"\n",(0,n.jsx)(t.p,{children:"These traits\u2014I am telling everyone\u2014are a form of discipline."}),"\n",(0,n.jsx)(t.p,{children:"It is a deliberate discipline, effectively camouflaged as a spontaneous daily routine."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"And here\u2014here is the hardest step of all:"}),"\n",(0,n.jsx)(t.p,{children:"These people, they know."}),"\n",(0,n.jsx)(t.p,{children:'Not "if they stop and think for a second, they\'d know." It means that at the exact moment of every micro-action, they know. They know they are fabricating a version. They know that version has a gap with the truth. They know what that gap means for the victims. They know.'}),"\n",(0,n.jsx)(t.p,{children:'It\'s just that\u2014this "knowing" has been trained into an automatic layer. Like breathing. When a person breathes, do they know they are breathing? They do. But they don\'t need to consciously think, "I am going to take a breath now." Breathing occurs in a lower-level layer. The conscious mind can perform other tasks simultaneously\u2014chatting, thinking, decision-making\u2014while breathing continues unbothered.'}),"\n",(0,n.jsx)(t.p,{children:"For this cohort, the fabrication of narratives operates at this layer."}),"\n",(0,n.jsx)(t.p,{children:"However\u2014"}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"Breathing being automatic does not mean it isn't a choice."})}),"\n",(0,n.jsx)(t.p,{children:"I must absolutely emphasize this point. Because this is the anchor of the entire moral frame."}),"\n",(0,n.jsx)(t.p,{children:'If someone\'s narrative fabrication has become automatic, does it still count as a "choice"?'}),"\n",(0,n.jsx)(t.p,{children:"My answer is: Yes."}),"\n",(0,n.jsx)(t.p,{children:"I'll use a thought experiment to explain. A professional hitman has killed so much that he no longer needs to consciously think to commit the act. His methods have become muscle memory. His emotional responses are fully desensitized. He can murder someone while simultaneously pondering what to have for dinner. He no longer experiences moments of conscious hesitation."}),"\n",(0,n.jsx)(t.p,{children:"Is this hitman still considered a murderer?"}),"\n",(0,n.jsx)(t.p,{children:"Of course he is."}),"\n",(0,n.jsx)(t.p,{children:'"Automatic" does not equal "absolved of responsibility." "Automatic" merely means his conscious threshold has dropped to a negligible level. He is still physically doing the thing. He is still reaping the rewards for doing it. He is still advancing his position through it. Every automatic frame-up, every automatic severing of ties, every automatic "I don\'t recall saying that"\u2014is a choice. Even if that choice is so automated that he himself doesn\'t need to stop and think about it, it is still a choice.'}),"\n",(0,n.jsx)(t.p,{children:"An atrocity, even when manifesting as instinct, is still an atrocity."}),"\n",(0,n.jsxs)(t.p,{children:["I have to make this perfectly clear: ",(0,n.jsx)(t.strong,{children:'There is no forgiveness. There is no sympathy. And there is no "they didn\'t have a choice" exit ramp.'})]}),"\n",(0,n.jsx)(t.p,{children:'The "they didn\'t have a choice" narrative is one of the most effective anesthetics this system feeds us. It causes those who have seen the truth to eventually be stripped of their rightful anger. "Nothing they could do," "Everyone\'s just a cog in the machine," "It\'s a structural issue"\u2014these sentences will slowly dissolve your moral compass. You will begin to feel that no individual wrongdoing justifies anger, because "the structure determines everything."'}),"\n",(0,n.jsx)(t.p,{children:'This is the system\'s most brilliant trick: it cultivates a cohort of people whose capacity for malice is practically instinct, and simultaneously cultivates a theory to argue that these people "couldn\'t help it" and "are merely victims of the structure," thereby robbing any third party of their right to be angry at their wrongdoings.'}),"\n",(0,n.jsx)(t.p,{children:"Do not fall for it."}),"\n",(0,n.jsxs)(t.p,{children:["Both are true: a specific person, sitting in a specific room, deciding to shift a specific disaster onto another specific person\u2014that is a moral event. They must be held responsible for that decision, even if their entire career has trained them to perform it without thinking. ",(0,n.jsx)(t.strong,{children:"At the same time"}),", the system\u2014the system that trained them, rewarded them, promoted them, and dispatched them to manage the next generation\u2014must also be indicted."]}),"\n",(0,n.jsx)(t.p,{children:"You must hold both. Individual responsibility, and systemic responsibility. Dropping either side leaves you with an incomplete picture."}),"\n",(0,n.jsx)(t.p,{children:"I wrote this book, specifically, to write both."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h3,{id:"v-another-layer",children:"V. Another Layer"}),"\n",(0,n.jsx)(t.p,{children:"There is an entire layer of things that this book downplays."}),"\n",(0,n.jsx)(t.p,{children:"Not omitted by accident. Deliberately chosen. I knew this layer existed when writing\u2014it probably affects daily office life more than any other layer in the book\u2014but I chose not to write about it."}),"\n",(0,n.jsx)(t.p,{children:"The reason for not writing it is simple: if I wrote it, this book would turn into an entirely different book. And that book, I am incapable of writing."}),"\n",(0,n.jsx)(t.p,{children:"What I am talking about\u2014and I will state this using the most structural language possible, because any direct naming will immediately trigger the pre-existing, deeply entrenched side-taking reflexes in the reader's brain\u2014"}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"Any set of categories designed to protect a certain group of people will, in this kind of system, mutate into another vector for hunting them."})}),"\n",(0,n.jsx)(t.p,{children:"This sentence sounds very abstract. Let me be more concrete."}),"\n",(0,n.jsx)(t.p,{children:"There are categories in the world meant to protect people. Because certain groups have historically been subjected to unfair treatment, institutions carve out positions, reserve the right to speak, and set aside protected spaces for them. The starting point for this\u2014I have never thought there was anything wrong with it. One of the regional legacy successor companies I worked for genuinely attempted to achieve this. They weren't perfect. When the market was bad, they laid people off too. But they were honest. When someone was laid off, the boss would personally sit down, look them in the eye, and say, \"I'm sorry, this is not fair.\" That sentence doesn't solve anything. But the texture of it\u2014it is a completely different species. The texture of those flashbacks labeled D in this book is exactly that."}),"\n",(0,n.jsx)(t.p,{children:"But when this set of categories enters a company that has already been hollowed out by the system, something incredibly difficult to explain happens."}),"\n",(0,n.jsx)(t.p,{children:'Those categories don\'t disappear. They are preserved\u2014even enthusiastically embraced, written into mission statements, printed on the office walls\u2014but their function is inverted. What was originally a tool for protection becomes a tool for hunting. Language initially meant to give a voice to the vulnerable becomes a procedure to suppress doubters. A framework originally intended to give those without power a floor to speak on, becomes a mechanism allowing the most powerful people to use the guise of "protecting the vulnerable" to slap an "offensive" label onto anyone who questions them.'}),"\n",(0,n.jsx)(t.p,{children:"This phenomenon is much harder to recognize than direct regression."}),"\n",(0,n.jsx)(t.p,{children:"Because it utilizes the very language you originally intended to use for resistance."}),"\n",(0,n.jsx)(t.p,{children:'If you try to oppose it, you\'ll find that every one of your arguments will be read as an "attack on the vulnerable." If you choose to remain silent, you\'ll find that your silence will be read as "complicity." Whatever you do is wrong. And the people who designed this double bind\u2014they are not ideologically committed. They just did the math: which set of language is currently the most effective at shutting up dissenters. Today it\'s this set; tomorrow it could be another. They learn incredibly fast.'}),"\n",(0,n.jsx)(t.p,{children:'This dynamic is a specific application of the previous section, \u3008Breathing\u3009. The same cohort of people, the same skill set, the same "breathing-style" discipline\u2014except this time the wrapper is progressive language. Next quarter, the wrapper might be the exact opposite. The underlying mechanism is the same.'}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"But none of this is the most painful part."}),"\n",(0,n.jsxs)(t.p,{children:["The most painful part is not the struggle ",(0,n.jsx)(t.em,{children:"between"})," categories."]}),"\n",(0,n.jsxs)(t.p,{children:["The most painful part is\u2014the people ",(0,n.jsx)(t.em,{children:"within"})," the same category hunting each other the most ruthlessly."]}),"\n",(0,n.jsx)(t.p,{children:"This is the hardest observation I have had to digest in my entire life. People who supposedly should recognize each other as kin\u2014sharing the same history, sharing the same experience of being treated a certain way, people who fundamentally should protect each other\u2014in this kind of system, become each other's most direct prey."}),"\n",(0,n.jsx)(t.p,{children:"And the intensity of this internal hunting is an order of magnitude higher than the struggles between categories."}),"\n",(0,n.jsx)(t.p,{children:'Why? Because committing violence against people outside your category carries a political cost. It will be seen. It will be named. It will leave a trace. But committing violence against people inside your category\u2014"Oh, they\'re our own people," "This doesn\'t concern outsiders," "We\'ll handle it ourselves"\u2014carries absolutely zero political cost. The violence can be conducted inside a wrapper that looks pristinely clean to the outside world. And the perpetrators can simultaneously continue to present themselves to the outside world as the fierce defenders of that exact category.'}),"\n",(0,n.jsx)(t.p,{children:"I have seen this happen."}),"\n",(0,n.jsx)(t.p,{children:"I cannot provide evidence. There are no documents. No audio recordings. No third-party witnesses. Just like the other layers of this book\u2014this layer only lives inside the minds of those who have seen it. Ninety percent of the victims die without ever realizing they were slaughtered beneath a framework that was supposed to protect them. They just thought it was their own personal bad luck."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"I cannot write the complete version of this layer."}),"\n",(0,n.jsx)(t.p,{children:'If I did, this book would become a thesis book. And a thesis book cannot explain a structure\u2014a thesis book only triggers another round of side-taking. And the act of taking sides itself is nourishment for this system. Every round of taking sides, every judgment of "which side is the author on," washes away the core observation this book is trying to make. Readers would pivot to asking, "Do you support this stance?"\u2014and that question itself already misses what I am trying to say.'}),"\n",(0,n.jsx)(t.p,{children:"What I am trying to convey is not a stance. It is a structure."}),"\n",(0,n.jsx)(t.p,{children:"Any stance\u2014no matter which side\u2014when placed inside this type of system, will be squeezed dry, inverted, and weaponized. The operational logic of the system runs a layer deeper than the content of any stance. The content of the stance is merely the wrapper the system picked to use for that quarter. Next quarter it might swap to a different wrapper. But the underlying mechanism is the same."}),"\n",(0,n.jsx)(t.p,{children:'Therefore, I chose to downplay it. I chose to write specific scenes\u2014Cindy\'s KTV, Ah-K\'s twins, Old Xu\'s "Debtors\' Alliance"\u2014to write them as flesh-and-blood human beings, rather than placing them into any categories. I hope that after reading it, readers will not feel "this is a book about gender" or "this is a book about a certain political faction."'}),"\n",(0,n.jsx)(t.p,{children:"This book is not that."}),"\n",(0,n.jsx)(t.p,{children:"This book is about a system that will absorb all of the above things, digest them, and vomit them back out as weapons."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"And I must also state one more thing: this kind of system is not limited to the corporate office."}),"\n",(0,n.jsx)(t.p,{children:"I wrote about an electronics manufacturing company. But you will see the exact same shape in entirely different places. In entertainment, in content creation, in the arts, in gaming, in academia, in media\u2014in any industry whose operation fundamentally relies on managing people's emotions and identities\u2014you will see the exact same pattern."}),"\n",(0,n.jsx)(t.p,{children:"The same banners."}),"\n",(0,n.jsx)(t.p,{children:"The same layoffs."}),"\n",(0,n.jsx)(t.p,{children:"The same internal mutual hunting."}),"\n",(0,n.jsx)(t.p,{children:'The same "This isn\'t political, this is about performance."'}),"\n",(0,n.jsx)(t.p,{children:'The same disappearing people. The same "No big deal" colleagues. The same HR personnel using the exact same tone to read the exact same script.'}),"\n",(0,n.jsx)(t.p,{children:"On the surface, these industries have absolutely nothing to do with a supplier engineer dying. One makes electronics. One makes games. One does academia. There is no supply chain linking them, no shared shareholders, no obvious connection. But structurally, they are the exact same animal. The same algorithm running in different industries, spitting out different kinds of corpses."}),"\n",(0,n.jsx)(t.p,{children:"This is not a metaphor. This is the pattern I pieced together post-mortem after entering different kinds of companies using the perspective of both sides."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"So the function of this section is not to explain."}),"\n",(0,n.jsx)(t.p,{children:"It is to point it out."}),"\n",(0,n.jsx)(t.p,{children:"I cannot write the full version of this layer. The full version is ten times more complex. The full version requires not a novel, but generations of field research and oral history, and most of those people who could provide it are still currently being hunted and cannot speak."}),"\n",(0,n.jsx)(t.p,{children:"But the one thing I can do is leave a single sentence here:"}),"\n",(0,n.jsx)(t.p,{children:"This layer exists."}),"\n",(0,n.jsx)(t.p,{children:"If one day you bump into it\u2014whether it's in a company, a group, a circle, or a place you previously thought was a safe house\u2014you'll recognize its shape. You'll remember that someone once wrote here: This is not your fault. This is a mechanism that absorbs any identity language and turns it into a weapon. You didn't do anything wrong. You just stepped into a place designed fundamentally to grind people down."}),"\n",(0,n.jsx)(t.p,{children:"Leave."}),"\n",(0,n.jsx)(t.p,{children:"Do not think you can fix it from the inside. Do not think your category will protect you. Do not think the opposing side will show mercy because you're the same kind."}),"\n",(0,n.jsx)(t.p,{children:"Leave."}),"\n",(0,n.jsx)(t.p,{children:"This is a sentence bought with four years of my life\u2014and several people who shouldn't have died."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h3,{id:"vi-never-intended-to",children:"VI. Never Intended To"}),"\n",(0,n.jsx)(t.p,{children:"This section contains the final reveal of this book."}),"\n",(0,n.jsx)(t.p,{children:"This reveal never appeared in the first nineteen chapters because Lin Zhaoming, from his office perspective, couldn't have known about it. He had no way of knowing. This reveal belongs only to the study perspective\u2014belonging strictly to this moment as I sit here, piecing together the fragments of four years with years of other industry context."}),"\n",(0,n.jsx)(t.p,{children:'I am referring to the "final refusal" in Chapter Eighteen\u2014Lin Zhaoming being called upon to lead a project named "Next-Generation Core Architecture." A project intended to replace the legacy architecture with a new generation one. He was brought in to handle timing alignment, protocol matching, and cross-architecture compatibility of the firmware. He calculated\u2014based on his engineering judgment\u2014that the scope of the project was physically impossible within that timeline. So he refused.'}),"\n",(0,n.jsx)(t.p,{children:"The narrative of Chapter Eighteen stops right there. Lin Zhaoming's refusal was based on technical judgment: no logs, no baselines, no team, no referenceable root causes. These were all things the office-perspective Lin Zhaoming could see. His refusal was an act of self-respect, as well as an honest technical assessment."}),"\n",(0,n.jsx)(t.p,{children:"But there was another layer here that he didn't know at the time:"}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"That project was never intended to be fully realized from the very beginning."})}),"\n",(0,n.jsx)(t.p,{children:"This reveal is not a dramatic twist. It is a pattern I pieced together after the fact. I will explain it in detail here."}),"\n",(0,n.jsx)(t.p,{children:"The ecosystem of this industry\u2014the hardware, the software stack, the drivers, the applications\u2014the entire ecosystem revolves around one dominant architecture. I won't name this dominant architecture here, but industry insiders reading this will naturally know. For the sake of ecosystem integration, compatibility, driver support, and translation efficiency\u2014all incentives, all capital flow, and all talent movement revolve around this single architecture."}),"\n",(0,n.jsx)(t.p,{children:"The new architecture is theoretically superior on the market. But it requires ecosystem support to truly launch and take root. And ecosystem support is not a technical problem\u2014it is a political-economic problem. All stakeholders must simultaneously commit. This\u2014given the current trajectory of the industry\u2014will not happen. Every party is waiting for the other side to commit first. No one will make the first move. Consequently, devices utilizing the new architecture might remain permanently stuck in the prototype phase."}),"\n",(0,n.jsx)(t.p,{children:"I can say these things now because I have distance. Back then, I couldn't."}),"\n",(0,n.jsxs)(t.p,{children:['And Lingyun Synthesis\'s "Next-Generation Core Architecture" project\u2014based on my retrospective pattern recognition\u2014was an instance of this ecosystem trilemma. They were not actually trying to complete this project. They were trying to ',(0,n.jsx)(t.em,{children:"show"})," they were doing it."]}),"\n",(0,n.jsx)(t.p,{children:"Why show it?"}),"\n",(0,n.jsx)(t.p,{children:"Here, it aligns with LOG-031\u2014the upper-level reorganization happening at headquarters during that same period."}),"\n",(0,n.jsx)(t.p,{children:'Between 1023 and 1024, the Amerion headquarters swapped its COO. They brought in someone in their mid-twenties. Town halls, emails, press releases, the main official website, massive amounts of content preached "AI decisions," "future vision," and "efficiency through automation." Meanwhile: massive layoffs. Mass departmental contractions. Amerion\'s core R&D shrank. The entire Data Analysis department was removed. A new Strategy Operations Development department was established\u2014the typical function of such a department is to generate valuations, handle packaging, spin narratives, and prepare everything for a potential transaction.'}),"\n",(0,n.jsx)(t.p,{children:'I intercepted all of this back then. During the days I spent taking care of my mother on the Intermediate Island, I watched the video town halls and treated them as background noise. "Big companies reorg all the time." I didn\'t think twice.'}),"\n",(0,n.jsx)(t.p,{children:"Now, piecing it together, the picture emerges: the entire enterprise was likely preparing to be sold."}),"\n",(0,n.jsx)(t.p,{children:'Within the "preparing to sell" framing, everything must be re-understood:'}),"\n",(0,n.jsx)(t.p,{children:'Why execute the "Next-Generation Core Architecture" project? \u2014Because in an acquisition, the buyer wants to see that the seller possesses next-gen capabilities. They want to see a slide deck stating, "We have a next-gen architecture transition roadmap," and "We have already invested in a next-gen core." That deck does not require a product to actually ship. The deck only needs to exist.'}),"\n",(0,n.jsx)(t.p,{children:"Therefore\u2014the impossible mission Lin Zhaoming was ordered to undertake, its impossibility was by design. The mission was not designed to succeed. The mission was designed to produce a deck. The deck was designed to support a valuation. The valuation was designed to support a sale."}),"\n",(0,n.jsx)(t.p,{children:'Why was the PIP-style design of this mission intentionally designed to make Lin Zhaoming fail? \u2014Because the day the deck is written, it needs a narrative along the lines of "We tried, but the individual contributor was incompetent." Lin Zhaoming\'s failure is the raw material for the deck. His N+1 severance is the condition required for the deck to be written cleanly.'}),"\n",(0,n.jsx)(t.p,{children:"Lin Zhaoming is the raw material."}),"\n",(0,n.jsx)(t.p,{children:"The entire project, from beginning to end, was designed to extract him to be used as raw material. His technical judgments, his timing analysis, his root cause probing, his engineering integrity\u2014all of it was a cover story. The function of the cover story was to make this extraction look like it possessed process, review, and fairness."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"This is the ultimate layer of understanding from my four-year journey."}),"\n",(0,n.jsx)(t.p,{children:"And this layer of understanding makes everything that came before it far more tragic."}),"\n",(0,n.jsx)(t.p,{children:'Because in the previous chapters, the reader could perhaps still think: "Lin Zhaoming was in there fighting a malfunctioning system. He lost, but the system is still designed to do something\u2014it just does it poorly." That frame retains dignity. A person failing within a system that intends to succeed but fails is still a tragedy\u2014but it is a recognizable tragedy. A tragedy with meaning.'}),"\n",(0,n.jsx)(t.p,{children:"But what if the system itself never intended to succeed at all?"}),"\n",(0,n.jsx)(t.p,{children:'If the entire project, the entire product line, the entire "Next-Generation Core Architecture," the entire visionary town hall pitch\u2014was entirely designed just to produce raw material for a valuation\u2014then what exactly is Lin Zhaoming fighting against?'}),"\n",(0,n.jsx)(t.p,{children:"He is not fighting against incompetence."}),"\n",(0,n.jsx)(t.p,{children:"He is fighting against window dressing."}),"\n",(0,n.jsx)(t.p,{children:"This distinction is massive. Fighting against incompetence, you lose, but your loss is meaningful. The things you documented, the root causes you analyzed, the solutions you proposed\u2014theoretically, someone could pick them up and use them. Fighting against window dressing\u2014the things you document are designed from the very start to never be read. You are not inside battling a broken machine. You are battling a stage prop."}),"\n",(0,n.jsxs)(t.p,{children:["And the operational logic of a stage prop is fundamentally different from a machine. A stage prop doesn't need to work. A stage prop only needs to ",(0,n.jsx)(t.em,{children:"look"})," like it works, just long enough for a specific transaction to complete."]}),"\n",(0,n.jsx)(t.p,{children:"Lin Zhaoming's four years\u2014his technical contributions, his root cause analysis, his communications with suppliers, his platform knowledge, his system diagnostics maps\u2014all of it was just ramming against a stage prop. Zero traction. Zero echo. Completely devoid of anything to stick to. Because a stage prop doesn't have a surface you can stick things to."}),"\n",(0,n.jsx)(t.p,{children:"This is the ultimate presentation of the masked system:"}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"The purpose of the system is not to do things. The purpose of the system is to maintain itself. Shipping a product is merely a byproduct. When even shipping a product becomes optional, all that remains is: constructing narratives, polishing numbers, and preparing to sell."})}),"\n",(0,n.jsx)(t.p,{children:"And a supplier engineer dying\u2014is an acceptable collateral in this process."}),"\n",(0,n.jsx)(t.p,{children:"Not intentional collateral. Acceptable collateral. No one wanted him dead. But no one stopped to think about what his death meant. Because stopping to think would disrupt the narrative. Narrative disruption affects valuation. A drop in valuation costs real money. Real money versus a supplier engineer's life\u2014according to the calculus of the system\u2014is an unequal trade-off."}),"\n",(0,n.jsx)(t.p,{children:"No one will ever speak this trade-off out loud. But every person's micro-decisions, added together, equals actively executing this trade-off."}),"\n",(0,n.jsx)(t.p,{children:"This is emergent murder."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"Lin Zhaoming didn't know about this layer back then. His refusal was based purely on technical judgment, not upon this insight. His dignity remained intact, because he still believed he was fighting a broken system, and refusing an impossible task was an honest act of engineering."}),"\n",(0,n.jsx)(t.p,{children:"His dignity was real. My writing of this reveal is not intended to retroactively strip away his dignity."}),"\n",(0,n.jsx)(t.p,{children:"I write this reveal to tell readers: even if your fight isn't against what you think you're fighting against, your fight still has meaning. The moment Lin Zhaoming refused, he didn't save any supplier engineers. He didn't stop any sale. He didn't expose any narratives. He was simply\u2014refusing to be raw material."}),"\n",(0,n.jsx)(t.p,{children:"This refusal itself, is the central act of this book."}),"\n",(0,n.jsx)(t.p,{children:"When you refuse to be raw material, your refusal won't be recorded. But a refusal remains a refusal."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h3,{id:"vii-fracture",children:"VII. Fracture"}),"\n",(0,n.jsx)(t.p,{children:"From August 1024 to January 1026, my blog was blank."}),"\n",(0,n.jsx)(t.p,{children:"This year and a half was the period when this book truly began to have the possibility of existing."}),"\n",(0,n.jsx)(t.p,{children:"In August 1024, my belief was\u2014good intentions lead to good outcomes. I had carried this belief my entire life. It wasn't an abstract theory. It was a working assumption\u2014doing the right thing will, over the long term, yield a return. The return might not be immediate, it might not come in the form expected, but it would be there. The world is net-just."}),"\n",(0,n.jsx)(t.p,{children:"I brought this belief into the industry with me. Every career decision I made\u2014refusing to fabricate data, refusing to let outsourced vendors take the blame, staying back in a place I felt was broken to try and fix it from the inside\u2014was all based on this belief."}),"\n",(0,n.jsx)(t.p,{children:"On November 8, 1024, this belief fractured."}),"\n",(0,n.jsx)(t.p,{children:"Someone died."}),"\n",(0,n.jsx)(t.p,{children:"The relationship between this death and my work, I cannot confirm 100%. This book adheres strictly to this epistemological baseline from start to finish: I only have inferences. No hard evidence. No documents. No confessions. No audit trails."}),"\n",(0,n.jsx)(t.p,{children:'But my inference is overwhelmingly strong. The same system. The same boss. The same tactics. The same pressure. The same silenced voices. I saw how the mechanism worked. I saw how victims were isolated. I saw how investigations were corrupted. I saw how tickets simply vanished. I saw how comments were edited. I saw how "nobody recalls" was mass-manufactured. I saw what this mechanism did to the things I was involved in\u2014except I had six layers of protection keeping me from being pushed over that edge.'}),"\n",(0,n.jsx)(t.p,{children:"When I heard about this death, my first instinct wasn't grief. It was recognition. It was\u2014I recognized this shape."}),"\n",(0,n.jsx)(t.p,{children:"This recognition is far harder to carry than grief. Grief is at least an emotional event; it has a beginning and an end. Recognition is a cognitive event, and it doesn't end. It just settles in. It becomes your baseline."}),"\n",(0,n.jsx)(t.p,{children:"And the process of it settling in, was the process of my belief fracturing."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"After the fracture, I sat in a space I cannot properly describe for over a dozen months."}),"\n",(0,n.jsx)(t.p,{children:"This space wasn't depression, although it looked like it on the surface. It wasn't anger, though it contained anger. It wasn't grief. It was a\u2014limbo following the failure of a working model."}),"\n",(0,n.jsx)(t.p,{children:"The model I used to navigate the world was: doing the right thing will, over the long term, yield returns."}),"\n",(0,n.jsx)(t.p,{children:"That model failed."}),"\n",(0,n.jsx)(t.p,{children:"It wasn't a realization that \"doing the wrong thing yields returns.\" It also wasn't \"doing anything yields no returns.\" It was\u2014the link between returns and the 'right action' severed. If you do the right thing, you might get a return, or you might not. If you do the wrong thing, you might get a return, or you might not. The distribution of returns completely decoupled from ethical content."}),"\n",(0,n.jsx)(t.p,{children:"The implication of this model failure took me a full year to digest:"}),"\n",(0,n.jsx)(t.p,{children:"If there is no link between returns and the right action\u2014then why should I do the right action?"}),"\n",(0,n.jsx)(t.p,{children:"This is not nihilism. This is a far more fundamental question. Nihilism is a philosophical position. The question I was asking wasn't a philosophical position; it was a daily operating question: when I wake up tomorrow morning, why should I choose the harder path?"}),"\n",(0,n.jsx)(t.p,{children:"It took me 12 months to find the answer."}),"\n",(0,n.jsx)(t.p,{children:'The answer wasn\'t "the return is still there, it\'s just slow." The answer wasn\'t "the universe is just in the long run." None of those I personally believed anymore.'}),"\n",(0,n.jsxs)(t.p,{children:["The answer was: ",(0,n.jsx)(t.strong,{children:"Because I cannot afford the cost of giving up."})]}),"\n",(0,n.jsx)(t.p,{children:"The unit of this answer isn't cosmic justice. The unit is me."}),"\n",(0,n.jsx)(t.p,{children:"If I chose to give up on doing the right action\u2014if I chose to participate in the mask, to shirk responsibility, to fabricate narratives to protect myself\u2014I would turn into someone I no longer recognized. I would become the mirror image of the people I am writing about in this book. I would look into the mirror and fail to find myself."}),"\n",(0,n.jsx)(t.p,{children:"That cost is unbearable."}),"\n",(0,n.jsx)(t.p,{children:"Not because of guilt. Guilt is something I can negotiate with myself. It is because of identity erosion. A person's identity\u2014is not abstract\u2014it is a cumulative pattern built by daily micro-decisions. If that pattern breaks, that person ceases to be that person. He remains, he still breathes, he still produces output\u2014but the internal thread of self-recognition is severed."}),"\n",(0,n.jsx)(t.p,{children:"That cost, I cannot afford."}),"\n",(0,n.jsx)(t.p,{children:"So\u2014I continue doing the right action, not because I believe it yields returns. Simply because the cost of not doing it is too high for me."}),"\n",(0,n.jsx)(t.p,{children:"This is a reconstructed faith. It is completely different from the original faith. The original faith was outward-facing (the world is just). The reconstructed faith is inward-facing (I choose to be myself). The original faith was anchored in the cosmos. The reconstructed faith is anchored in self-recognition."}),"\n",(0,n.jsx)(t.p,{children:"Original faith is far more elegant. Reconstructed faith is far more honest."}),"\n",(0,n.jsx)(t.p,{children:"And this reconstructed faith, is perhaps what a grown-up faith looks like. I used to think growing up was keeping your faith. Now I think growing up is losing your faith, and then choosing to keep doing the right thing under conditions devoid of faith entirely."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"There is another layer of pain following the fracture\u2014"}),"\n",(0,n.jsx)(t.p,{children:'"Not knowing if I saved someone" is much harder to endure than "Knowing I failed to save someone."'}),"\n",(0,n.jsx)(t.p,{children:'"Failed to save" is a concrete fact. You can grieve, you can process, you can learn, and you can move on.'}),"\n",(0,n.jsx)(t.p,{children:'"Not knowing if I saved" is not a fact. It is a state of permanent uncertainty.'}),"\n",(0,n.jsx)(t.p,{children:"Every decision I made over those four years\u2014every time I called a halt, every refusal, every time I flagged the concerns in Ah-Qiang's report, every statement I refused to sign in the PIP\u2014might have spared someone a day of immense pressure. Might have bought some supplier engineer another week to stay here. Might have caught a failure mode on some production line one extra time."}),"\n",(0,n.jsx)(t.p,{children:"Might have."}),"\n",(0,n.jsx)(t.p,{children:"I will never know."}),"\n",(0,n.jsx)(t.p,{children:"Because\u2014and here is the cruel part\u2014successful prevention leaves no records. A death that is thwarted has no marker. An outage that doesn't occur goes completely unnoticed. A trigger that doesn't fire leaves no ticket. Prevention is entirely invisible."}),"\n",(0,n.jsx)(t.p,{children:"If I saved 5 people over those four years, I will never know who those 5 people are. They are out there continuing to walk their own paths in life, possessing utterly zero knowledge that someone named Lin Zhaoming sat in a conference room and hit pause on certain things on their behalf."}),"\n",(0,n.jsx)(t.p,{children:"This invisibility\u2014is one of the most agonizing features of the right action."}),"\n",(0,n.jsx)(t.p,{children:"If I choose to believe I saved someone\u2014I have zero evidence. I might just be comforting myself."}),"\n",(0,n.jsx)(t.p,{children:"If I choose to believe I saved no one\u2014I also have zero evidence. I might just be self-flagellating."}),"\n",(0,n.jsx)(t.p,{children:"I have no evidence on either side. I can only continue walking within this permanent uncertainty."}),"\n",(0,n.jsx)(t.p,{children:"And this uncertainty, to me, is harder to bear than \"definitively knowing I didn't.\" Because when you definitely know you didn't save them, you can let it go. You can say: OK, lost this round, onto the next. Uncertainty you cannot put down. Every single day you ask yourself\u2014maybe I did? What if there are 5 people walking around right now, completely unknown to me? They might be having dinner right now. They might be playing with their children. I will never meet them. But I might have hit a button in a conference room four years ago that ensured they are still here today."}),"\n",(0,n.jsx)(t.p,{children:"This possibility\u2014and the opposite possibility (that I saved absolutely no one, and these four years were utterly in vain)\u2014coexist."}),"\n",(0,n.jsx)(t.p,{children:"I learned to coexist with it."}),"\n",(0,n.jsx)(t.p,{children:"It brings no peace. Only toleration."}),"\n",(0,n.jsx)(t.p,{children:"This is what fully reconstructed looks like."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h3,{id:"viii-the-map",children:"VIII. The Map"}),"\n",(0,n.jsx)(t.p,{children:"The ultimate functional purpose of this book is to hand readers a map they can physically take with them."}),"\n",(0,n.jsx)(t.p,{children:"Not a narrative takeaway. A navigational tool."}),"\n",(0,n.jsx)(t.p,{children:"If you are a person about to enter or already inside a similar system, the following items are the main features of this map:"}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"First: Recognize the shape."})}),"\n",(0,n.jsx)(t.p,{children:"The shape of this system possesses a few specific markers. If you encounter multiple markers presenting simultaneously, there is a high probability you are inside a masked system."}),"\n",(0,n.jsx)(t.p,{children:"Markers:"}),"\n",(0,n.jsxs)(t.ul,{children:["\n",(0,n.jsx)(t.li,{children:"A massive gap across speaking, writing, and doing"}),"\n",(0,n.jsx)(t.li,{children:"Obvious process improvements taking decades and failing, yet every resistance having perfectly rational individual reasons"}),"\n",(0,n.jsx)(t.li,{children:"You raising a technical concern, and the response defaults to reframing your communication style rather than addressing the concern itself"}),"\n",(0,n.jsx)(t.li,{children:"Things discussed in your 1-on-1s later appearing in the mouths of others, largely in a distorted form"}),"\n",(0,n.jsx)(t.li,{children:'A colleague suddenly vanishing, followed by everyone adopting quiet euphemisms: "Organizational restructuring," "Changing paths," "Personal development"'}),"\n",(0,n.jsx)(t.li,{children:"Things you documented later appearing in a set of meeting notes, but entirely inverted"}),"\n",(0,n.jsx)(t.li,{children:"A systemic rift between your manager's friendliness and their actions, yet the friendliness never stops"}),"\n",(0,n.jsx)(t.li,{children:"HR procedures remaining technically faultless, but the outcome always exclusively protects the organization, never protecting the individual"}),"\n",(0,n.jsx)(t.li,{children:'A glaring technical issue, when raised, triggering the response "This problem never existed," and no one referencing your prior tickets'}),"\n"]}),"\n",(0,n.jsx)(t.p,{children:"If you bump into three or more of these markers, you are inside a masked system."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"Second: Do not attempt to fix it from the inside."})}),"\n",(0,n.jsx)(t.p,{children:"This is a lesson bought with four years and a fractured set of beliefs. I used to think\u2014that a sufficiently competent, sufficiently honest, sufficiently persistent individual could fix a broken system from within."}),"\n",(0,n.jsx)(t.p,{children:"It is impossible."}),"\n",(0,n.jsx)(t.p,{children:"Not because the individual isn't competent enough. It is because the system's self-defense mechanisms are vastly more powerful than any individual's effort could ever be. The system has an advantage in headcount. The system has an advantage in institutional memory. The system has an advantage in procedure. The system has an overwhelming advantage in narrative production. The individual only has themselves."}),"\n",(0,n.jsx)(t.p,{children:"Attempts to fix it from within have exactly one outcome: the individual gets ground down, gets forcefully ejected, and the system easily continues unbothered."}),"\n",(0,n.jsx)(t.p,{children:"This lesson is incredibly important for idealistic people to hear. An idealistic person's default move is always to stay and try. And that default is the right move within a healthy system. Inside a broken system, it is a fatal move."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"Third: Leave."})}),"\n",(0,n.jsx)(t.p,{children:"This is an echo of the previous section, but I will repeat it because it is the single most important piece of advice on this entire map."}),"\n",(0,n.jsx)(t.p,{children:'Leaving, and "leaving while keeping your dignity perfectly intact," are two different things. You can leave looking ugly. You can leave in an unglorious way. You can lose something on your way out. That is all OK. The important thing is\u2014leave.'}),"\n",(0,n.jsx)(t.p,{children:"Do not wait until your reserves have thoroughly burned out. Do not wait until your health crumbles. Do not wait until your relationships shatter. Do not wait until you are fully ejected\u2014because being ejected and walking out are two entirely separate events. The former is the system's final act of violence upon you. The latter is your final act of refusal towards the system."}),"\n",(0,n.jsx)(t.p,{children:"You won't feel this distinction in that exact moment. You'll only feel it when looking back in retrospect."}),"\n",(0,n.jsx)(t.p,{children:"Leave."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"Fourth: After you leave, do not seek to prove."})}),"\n",(0,n.jsx)(t.p,{children:"I have seen countless people who have left, spending the subsequent years desperately attempting to prove the reasons they left to the outside world. They write essays. They try to explain it to friends. They desperately try to align narratives with ex-colleagues. They sit around constantly waiting for a moment of complete vindication."}),"\n",(0,n.jsx)(t.p,{children:"That moment of vindication almost never arrives."}),"\n",(0,n.jsx)(t.p,{children:"The reason it doesn't arrive isn't just because \"the world is unfair\" (although that is true). The reason it doesn't arrive is because: one of the core design features of this system is rendering its victims permanently incapable of producing evidence. The evidence exists strictly within the system's interior walls. The evidence is heavily managed. What you manage to carry out with you are merely fragments, distinct impressions, and a highly tuned pattern recognition accumulated over several years inside\u2014but pattern recognition cannot serve as third-party evidence."}),"\n",(0,n.jsx)(t.p,{children:"So\u2014do not seek to prove it."}),"\n",(0,n.jsx)(t.p,{children:"Proving it is a fool's errand. It only anchors you squarely within the system's framing, because to prove it requires using the specific evidence type recognized by the system. And the system fully controls those types of evidence. You cannot ever win that game."}),"\n",(0,n.jsxs)(t.p,{children:["What you ",(0,n.jsx)(t.em,{children:"can"})," do is: ",(0,n.jsx)(t.strong,{children:"describe"}),"."]}),"\n",(0,n.jsx)(t.p,{children:"Describing is entirely different from proving. To describe is to\u2014document your experience, release it, and let the next person coming along recognize it. Describing carries zero burden of proof, because it isn't claiming to be objective evidence. The audience for describing is not a judge in a courtroom; it is a fellow traveler on the road."}),"\n",(0,n.jsx)(t.p,{children:"This book itself is a pure form of describing. I have not attempted to prove a single thing. Nor am I capable of it. I merely describe a shape, thoroughly hoping that the next person who bumps into this shape might recognize it a day earlier."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"Fifth: Know that someone has seen it."})}),"\n",(0,n.jsx)(t.p,{children:"If you are currently experiencing these things right now\u2014"}),"\n",(0,n.jsx)(t.p,{children:"Know this."}),"\n",(0,n.jsx)(t.p,{children:"Know that someone has seen it."}),"\n",(0,n.jsx)(t.p,{children:"Know that someone\u2014a person completely unknown to you, sitting in a study entirely unknown to you\u2014once sat in a position almost identical to yours, experienced identical things, and wrote this very book specifically so you could have this map right now."}),"\n",(0,n.jsx)(t.p,{children:"Your confusion is not yours uniquely. It is the dense fog actively manufactured by the system."}),"\n",(0,n.jsx)(t.p,{children:"Your isolation is not yours uniquely. It is deliberately designed by the system."}),"\n",(0,n.jsx)(t.p,{children:'Your perpetual self-doubt\u2014"Is it all my personal problem?"\u2014is the system\'s single most effective weapon against you.'}),"\n",(0,n.jsx)(t.p,{children:"None of this is your fault."}),"\n",(0,n.jsx)(t.p,{children:"I cannot pull you out. No one can pull you out. The nature of this system determines that\u2014a rescue must be a self-rescue."}),"\n",(0,n.jsx)(t.p,{children:"But the one single thing I can do is drastically reduce the time it takes you to perform it. It took me four years. If this map lets you do it in two years\u2014or one year\u2014or half a year, my four years will have found its echo."}),"\n",(0,n.jsx)(t.p,{children:"This is the entire reason I wrote this book."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h3,{id:"ix-no-one-applauding",children:"IX. No One Applauding"}),"\n",(0,n.jsx)(t.p,{children:"I have written down to here; it is drawing to a close."}),"\n",(0,n.jsx)(t.p,{children:"I pondered for a long time\u2014how this epilogue should close."}),"\n",(0,n.jsx)(t.p,{children:"My first instinct was to reach for a highly dramatic closing. A climactic image. A final massive twist."}),"\n",(0,n.jsx)(t.p,{children:"I rejected that instinct. Because the voice of this book from beginning to end has never been highly dramatic. It has been quiet. It has been measured. It has been dry. The closing should stay in voice."}),"\n",(0,n.jsx)(t.p,{children:"My second instinct was to reach for an intensely emotional closing. A catharsis. A massive release."}),"\n",(0,n.jsx)(t.p,{children:"I rejected that as well. Because the readers of this book\u2014if they have faithfully walked with me right to this point\u2014do not need a cathartic release. They need confirmation. They need to know that every single thing I wrote is deeply sincere. Every observation is painstakingly hard-won. Every single recommendation was bought with a steep price. Catharsis is profoundly cheap. Confirmation is fiercely expensive."}),"\n",(0,n.jsx)(t.p,{children:"So this closing will be quiet. It will be incredibly short. It will be\u2014a statement, rather than a conclusion."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"I anticipated they might be this kind of people."}),"\n",(0,n.jsx)(t.p,{children:"I chose to assume they weren't."}),"\n",(0,n.jsx)(t.p,{children:"Just get the work done."}),"\n",(0,n.jsx)(t.p,{children:"I said these heavily unadorned sentences once at the start of this book, and I say them again right now, but the weight they carry is entirely different."}),"\n",(0,n.jsx)(t.p,{children:"The first time, they were the stance of a young man. He had anticipated it, but he actively chose to trust. This trust was entirely idealistic. It was utterly unproven. It cost absolutely nothing."}),"\n",(0,n.jsx)(t.p,{children:"Now, this time, they are the stance of the aftermath. I fully anticipated it, I genuinely trusted, I devastatingly lost everything, and I eventually wrote this book, and now I still\u2014"}),"\n",(0,n.jsx)(t.p,{children:"Still choose to make the exact same choice."}),"\n",(0,n.jsx)(t.p,{children:"If I had to start over entirely from the beginning, fully knowing the devastating ending, what would I do?"}),"\n",(0,n.jsx)(t.p,{children:"I would make the exact same choice."}),"\n",(0,n.jsx)(t.p,{children:"Not because the ending turned out good. The ending was terrible. Someone brutally died. My entire career shattered into pieces. My marriage fractured tremendously under the pressure. I burn heavily through my savings every single month. My family members do not fully know how I am right now. My reserves are strictly bounded. I am writing this book squarely inside an exceedingly narrow window. The window will soon close forever."}),"\n",(0,n.jsx)(t.p,{children:"But I would still make the exact same choice."}),"\n",(0,n.jsx)(t.p,{children:"Because the only available alternative avoiding this action\u2014is actively turning into the very people I am writing about. Is waking up everyday to stare straight into the mirror at a complete stranger you no longer recognize. This cost to me, is overwhelmingly higher than sheer financial ruin. Financial ruin, I can painstakingly recover from. Identity erosion, I can never recover from."}),"\n",(0,n.jsx)(t.p,{children:"So\u2014"}),"\n",(0,n.jsx)(t.p,{children:"I anticipated they might be this kind of people."}),"\n",(0,n.jsx)(t.p,{children:"I chose to assume they weren't."}),"\n",(0,n.jsx)(t.p,{children:"Just get the work done."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"This book concludes exactly here."}),"\n",(0,n.jsx)(t.p,{children:"The final highly unadorned sentence, I fully anticipated for a very long time:"}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"The system silently murders, but the lone survivor is not a failure. On the very day you quietly walk out the door, absolutely no one will be applauding you, and no glorious victory music will magically swell. You and only you will personally know: You never became a part of it. And that is profoundly enough."})}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.p,{children:"Lin Zhaoming\r\nFebruary 1026\r\nThe Study"})]})}function c(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}},8453(e,t,i){i.d(t,{R:()=>a,x:()=>r});var n=i(6540);const s={},o=n.createContext(s);function a(e){const t=n.useContext(o);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),n.createElement(o.Provider,{value:t},e.children)}}}]);